     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Button } from "@/components/ui/button";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Textarea } from "@/components/ui/textarea";
     9→import { Switch } from "@/components/ui/switch";
    10→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    11→import type { Project, ProjectInput } from "@/lib/api/types";
    12→
    13→interface ProjectFormProps {
    14→  initial?: Project;
    15→  onSubmit: (input: ProjectInput) => Promise<void>;
    16→  title: string;
    17→}
    18→
    19→export function ProjectForm({ initial, onSubmit, title }: ProjectFormProps) {
    20→  const router = useRouter();
    21→  const [saving, setSaving] = useState(false);
    22→  const [name, setName] = useState(initial?.name ?? "");
    23→  const [description, setDescription] = useState(initial?.description ?? "");
    24→  const [agentPrompt, setAgentPrompt] = useState(initial?.agent_prompt ?? "");
    25→  const [onMajor, setOnMajor] = useState(initial?.agent_rules?.on_major_release ?? true);
    26→  const [onMinor, setOnMinor] = useState(initial?.agent_rules?.on_minor_release ?? false);
    27→  const [onSecurity, setOnSecurity] = useState(initial?.agent_rules?.on_security_patch ?? true);
    28→  const [versionPattern, setVersionPattern] = useState(initial?.agent_rules?.version_pattern ?? "");
    29→  const [error, setError] = useState("");
    30→
    31→  const handleSubmit = async (e: React.FormEvent) => {
    32→    e.preventDefault();
    33→    setError("");
    34→    setSaving(true);
    35→    try {
    36→      await onSubmit({
    37→        name,
    38→        description: description || undefined,
    39→        agent_prompt: agentPrompt || undefined,
    40→        agent_rules: {
    41→          on_major_release: onMajor,
    42→          on_minor_release: onMinor,
    43→          on_security_patch: onSecurity,
    44→          version_pattern: versionPattern || undefined,
    45→        },
    46→      });
    47→      router.push("/projects");
    48→    } catch (err: unknown) {
    49→      setError(err instanceof Error ? err.message : "Failed to save");
    50→    } finally {
    51→      setSaving(false);
    52→    }
    53→  };
    54→
    55→  return (
    56→    <Card className="mx-auto max-w-2xl">
    57→      <CardHeader>
    58→        <CardTitle>{title}</CardTitle>
    59→      </CardHeader>
    60→      <CardContent>
    61→        <form onSubmit={handleSubmit} className="space-y-4">
    62→          {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    63→          <div className="space-y-2">
    64→            <Label htmlFor="name">Name</Label>
    65→            <Input id="name" value={name} onChange={(e) => setName(e.target.value)} required />
    66→          </div>
    67→          <div className="space-y-2">
    68→            <Label htmlFor="description">Description</Label>
    69→            <Textarea id="description" value={description} onChange={(e) => setDescription(e.target.value)} rows={2} />
    70→          </div>
    71→          <div className="space-y-2">
    72→            <Label htmlFor="agent_prompt">Agent Prompt</Label>
    73→            <Textarea
    74→              id="agent_prompt"
    75→              value={agentPrompt}
    76→              onChange={(e) => setAgentPrompt(e.target.value)}
    77→              rows={6}
    78→              placeholder="Custom instructions for the agent when analyzing releases for this project..."
    79→              className="font-mono text-sm"
    80→            />
    81→          </div>
    82→          <div className="space-y-3">
    83→            <Label>Agent Rules</Label>
    84→            <div className="rounded-md border p-4 space-y-3">
    85→              <div className="flex items-center gap-3">
    86→                <Switch checked={onMajor} onCheckedChange={setOnMajor} />
    87→                <Label>Trigger on major releases</Label>
    88→              </div>
    89→              <div className="flex items-center gap-3">
    90→                <Switch checked={onMinor} onCheckedChange={setOnMinor} />
    91→                <Label>Trigger on minor releases</Label>
    92→              </div>
    93→              <div className="flex items-center gap-3">
    94→                <Switch checked={onSecurity} onCheckedChange={setOnSecurity} />
    95→                <Label>Trigger on security patches</Label>
    96→              </div>
    97→              <div className="space-y-2">
    98→                <Label htmlFor="version_pattern">Version Pattern (regex, optional)</Label>
    99→                <Input
   100→                  id="version_pattern"
   101→                  value={versionPattern}
   102→                  onChange={(e) => setVersionPattern(e.target.value)}
   103→                  placeholder='e.g. ^v\d+\.\d+\.\d+$'
   104→                />
   105→              </div>
   106→            </div>
   107→          </div>
   108→          <div className="flex justify-end gap-2">
   109→            <Button type="button" variant="outline" onClick={() => router.back()}>Cancel</Button>
   110→            <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   111→          </div>
   112→        </form>
   113→      </CardContent>
   114→    </Card>
   115→  );
   116→}
   117→

